import React from 'react';
import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useLang } from '../context/LangContext';
import './ProductCard.css';

const CATEGORY_IMAGES = {
  'flours-mixes': [
    'https://images.unsplash.com/photo-1574323347407-f5e1ad6d020b?w=400&q=80',
    'https://images.unsplash.com/photo-1586201375761-83865001e31c?w=400&q=80',
    'https://images.unsplash.com/photo-1587401987695-2f36e29c9a55?w=400&q=80',
  ],
  'millets': [
    'https://images.unsplash.com/photo-1586201375761-83865001e31c?w=400&q=80',
    'https://images.unsplash.com/photo-1574323347407-f5e1ad6d020b?w=400&q=80',
  ],
  'rice-pulses': [
    'https://images.unsplash.com/photo-1516684732162-798a0062be99?w=400&q=80',
    'https://images.unsplash.com/photo-1546069901-5ec6a79120b0?w=400&q=80',
  ],
  'spices-powders': [
    'https://images.unsplash.com/photo-1596040033229-a9821ebd058d?w=400&q=80',
    'https://images.unsplash.com/photo-1506368249639-73a05d6f6488?w=400&q=80',
    'https://images.unsplash.com/photo-1588315029754-2dd089d39a1a?w=400&q=80',
  ],
  'natural-care': [
    'https://images.unsplash.com/photo-1556228720-195a672e8a03?w=400&q=80',
    'https://images.unsplash.com/photo-1608248597279-f99d160bfcbc?w=400&q=80',
  ],
  'cold-pressed-oils': [
    'https://images.unsplash.com/photo-1474979266404-7eaacbcd87c5?w=400&q=80',
    'https://images.unsplash.com/photo-1608248543803-ba4f8c70ae0b?w=400&q=80',
  ],
  'pickles': [
    'https://images.unsplash.com/photo-1589135716383-9f98e8a2e6e4?w=400&q=80',
    'https://images.unsplash.com/photo-1535189043414-47a3c49a0bed?w=400&q=80',
  ],
  'sweeteners-snacks': [
    'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&q=80',
    'https://images.unsplash.com/photo-1590080875897-bcca9dfb29ae?w=400&q=80',
  ],
};

const getProductImage = (product) => {
  if (product.image_url) return product.image_url;
  const slug = product.categories?.slug || 'flours-mixes';
  const imgs = CATEGORY_IMAGES[slug] || CATEGORY_IMAGES['flours-mixes'];
  // Use product name hash for consistent image assignment
  const idx = product.name.charCodeAt(0) % imgs.length;
  return imgs[idx];
};

const ProductCard = ({ product }) => {
  const { addToCart } = useCart();
  const { lang, t } = useLang();

  const displayName = lang === 'te' && product.name_telugu ? product.name_telugu : product.name;

  return (
    <div className="product-card">
      <Link to={`/product/${product.slug}`} className="product-card-image-wrap">
        <img
          src={getProductImage(product)}
          alt={product.name}
          className="product-card-image"
          loading="lazy"
        />
        {product.is_featured && (
          <span className="product-badge">{t('Featured', 'ఫీచర్డ్')}</span>
        )}
        <div className="product-card-hover">
          <span>{t('View Details', 'వివరాలు చూడండి')} →</span>
        </div>
      </Link>

      <div className="product-card-body">
        <p className="product-category eyebrow">
          {t(product.categories?.name || '', product.categories?.name_telugu || '')}
        </p>
        <h3 className="product-name">
          <Link to={`/product/${product.slug}`}>{displayName}</Link>
        </h3>
        <div className="product-card-footer">
          <div className="product-price">
            {product.price > 0
              ? <span>₹{product.price.toFixed(2)} <small>/ {product.unit}</small></span>
              : <span className="price-tbd">{t('Price on request', 'ధర అభ్యర్థనపై')}</span>
            }
          </div>
          <button
            className="add-to-cart-btn"
            onClick={() => addToCart(product)}
            title={t('Add to bag', 'బ్యాగ్‌కి చేర్చండి')}
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;
